#!/usr/bin/env bash\n# 鐢?Let's Encrypt锛坈ertbot锛夌鍙戠殑璇佷功鏇挎崲 IKEv2 鏈嶅姟绔瘉涔︼紝Windows 鏃犻渶鍐嶅鍏ヨ嚜绛?CA銆?
#\n# 鍓嶇疆:\n#   - 宸叉湁鍩熷悕 A 璁板綍鎸囧悜鏈満鍏綉 IP\n#   - 鏈満 80 鍙煭鏆傚崰鐢紙standalone锛夛紝鎴栧凡閰嶅ソ web/nginx 鎻掍欢 / DNS-01\n#   - 宸叉寜 install.sh 瑁呭ソ StrongSwan + swanctl锛?etc/swanctl/conf.d/10-ikev2-eap.conf 绛夛級\n#\n# 棣栨鐢宠绀轰緥:\n#   sudo apt install certbot\n#   sudo certbot certonly --standalone -d vpn.example.com\n#\n# 閮ㄧ讲鍒?StrongSwan:\n#   sudo LE_DOMAIN=vpn.example.com bash scripts/apply-letsencrypt-to-swanctl.sh\n#\n# certbot 缁湡閮ㄧ讲閽╁瓙锛堟帹鑽愶級:\n#   sudo cp scripts/apply-letsencrypt-to-swanctl.sh /usr/local/sbin/\n#   sudo bash -c 'cat > /etc/letsencrypt/renewal-hooks/deploy/strongswan-swanctl.sh << "DEP"\n#!/bin/bash\nexport LE_DOMAIN="${RENEWED_DOMAINS%% *}"\n/usr/local/sbin/apply-letsencrypt-to-swanctl.sh\nDEP'\n#   sudo chmod +x /etc/letsencrypt/renewal-hooks/deploy/strongswan-swanctl.sh\n#\n# Certbot 缁湡閽╁瓙鐜鍙橀噺: RENEWED_LINEAGE, RENEWED_DOMAINS\nset -euo pipefail\n\nif [[ "$(id -u)" -ne 0 ]]; then\n  echo "璇蜂娇鐢?root 杩愯銆?\n  exit 1\nfi\n\nif [[ -n "${RENEWED_LINEAGE:-}" ]]; then\n  LIVE="${RENEWED_LINEAGE}"\n  LE_DOMAIN="${LE_DOMAIN:-${RENEWED_DOMAINS%% *}}"\nelse\n  LIVE="${LE_LIVE:-}"\n  if [[ -z "${LIVE}" && -n "${LE_DOMAIN:-}" ]]; then\n    LIVE="/etc/letsencrypt/live/${LE_DOMAIN}"\n  fi\nfi\n\nif [[ -z "${LE_DOMAIN:-}" ]]; then\n  echo "璇疯缃?LE_DOMAIN锛堥』涓庤瘉涔︿富鍚嶄竴鑷达紝涓?Windows銆屾湇鍔″櫒鍦板潃銆嶅～姝ゅ煙鍚嶏級銆?\n  echo "鎴栫敱 certbot deploy 閽╁瓙浼犲叆 RENEWED_DOMAINS銆?\n  exit 1\nfi\n\nif [[ ! -f "${LIVE}/fullchain.pem" || ! -f "${LIVE}/privkey.pem" ]]; then\n  echo "鎵句笉鍒拌瘉涔? ${LIVE}/fullchain.pem 鎴?privkey.pem"\n  exit 1\nfi\n\nSWAN_X509="/etc/swanctl/x509"\nSWAN_KEY="/etc/swanctl/private"\ninstall -d -m 0755 "${SWAN_X509}" "${SWAN_KEY}"\n\ninstall -m 0644 "${LIVE}/fullchain.pem" "${SWAN_X509}/vpn-server-cert.pem"\ninstall -m 0600 "${LIVE}/privkey.pem" "${SWAN_KEY}/vpn-server-key.pem"\n\n# 绉侀挜绫诲瀷锛圠E 鍙兘鏄?RSA 鎴?ECDSA锛?
KEYTYPE=rsa\nif openssl ec -in "${SWAN_KEY}/vpn-server-key.pem" -noout 2>/dev/null; then\n  KEYTYPE=ecdsa\nfi\n\nEAP_CONF="/etc/swanctl/conf.d/20-eap-users.conf"\nif [[ -f "${EAP_CONF}" ]]; then\n  sed -i "s/^\([[:space:]]*\)type = \(rsa\|ecdsa\)\$/\1type = ${KEYTYPE}/" "${EAP_CONF}"\nfi\n\n# swanctl 韬唤椤讳笌璇佷功涓殑 CN/SAN 涔嬩竴涓€鑷达紙鍩熷悕鍓嶅姞 @锛?
if [[ "${LE_DOMAIN}" =~ ^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+$ ]]; then\n  SWAN_ID="${LE_DOMAIN}"\nelse\n  SWAN_ID="@${LE_DOMAIN}"\nfi\n\nIKEV2_CONF="/etc/swanctl/conf.d/10-ikev2-eap.conf"\nif [[ -f "${IKEV2_CONF}" ]]; then\n  sed -i "s|^[[:space:]]*id = .*$|      id = ${SWAN_ID}|" "${IKEV2_CONF}"\n  sed -i "s|^[[:space:]]*certs = .*$|      certs = vpn-server-cert.pem|" "${IKEV2_CONF}"\nfi\n\nif systemctl is-active --quiet strongswan-starter 2>/dev/null; then\n  :\nelif systemctl is-active --quiet strongswan 2>/dev/null; then\n  :\nelse\n  systemctl start strongswan-starter 2>/dev/null || systemctl start strongswan 2>/dev/null || true\nfi\n\nsleep 1\nswanctl --load-all --file /etc/swanctl/swanctl.conf\n\necho "宸插姞杞?Let's Encrypt 璇佷功锛沇indows 浣跨敤 IKEv2锛屾湇鍔″櫒濉? ${LE_DOMAIN}"\necho "锛堢郴缁熷凡淇′换鍏叡 CA锛屼竴鑸棤闇€鍐嶅畨瑁?ca-cert.pem锛?\n